# Block Brawl Audio -> MIDI Converter
# Generates a multi-track MIDI file from the game's synthesized audio data

$OutputFile = "$PSScriptRoot\BlockBrawl_Tracks.mid"
$BPM = 140
$TPQ = 480

function Write-VarLen([System.IO.BinaryWriter]$w, [int]$value) {
    $bytes = [System.Collections.Generic.List[byte]]::new()
    $bytes.Add([byte]($value -band 0x7F))
    $value = $value -shr 7
    while ($value -gt 0) {
        $bytes.Insert(0, [byte](($value -band 0x7F) -bor 0x80))
        $value = $value -shr 7
    }
    $w.Write([byte[]]$bytes.ToArray())
}

function FreqToMidi([double]$freq) {
    if ($freq -le 0) { return 60 }
    $n = [int][Math]::Round(69 + 12 * [Math]::Log($freq / 440.0, 2))
    return [Math]::Max(0, [Math]::Min(127, $n))
}

function SecsToTicks([double]$secs) {
    return [int][Math]::Round($secs * $TPQ * $BPM / 60.0)
}

function GainVel([double]$g) {
    return [Math]::Max(1, [Math]::Min(127, [int][Math]::Round($g * 127)))
}

function Write-Track([System.IO.BinaryWriter]$mainWriter, [string]$name, [int]$channel, [int]$program, [System.Collections.Generic.List[hashtable]]$events, [bool]$includeTempo) {
    $ms = [System.IO.MemoryStream]::new()
    $bw = [System.IO.BinaryWriter]::new($ms)

    # Track name
    $nameBytes = [System.Text.Encoding]::ASCII.GetBytes($name)
    $bw.Write([byte]0x00)
    $bw.Write([byte[]](0xFF, 0x03))
    Write-VarLen $bw $nameBytes.Length
    $bw.Write($nameBytes)

    # Tempo (first track only)
    if ($includeTempo) {
        $bw.Write([byte]0x00)
        $bw.Write([byte[]](0xFF, 0x51, 0x03))
        $uspb = [int](60000000 / $BPM)
        $bw.Write([byte](($uspb -shr 16) -band 0xFF))
        $bw.Write([byte](($uspb -shr 8) -band 0xFF))
        $bw.Write([byte]($uspb -band 0xFF))
    }

    # Program change
    $bw.Write([byte]0x00)
    $bw.Write([byte](0xC0 -bor $channel))
    $bw.Write([byte]$program)

    # Sort events and write
    $sorted = $events | Sort-Object { $_.tick }, { $_.on }
    $lastTick = 0
    foreach ($evt in $sorted) {
        $delta = $evt.tick - $lastTick
        if ($delta -lt 0) { $delta = 0 }
        Write-VarLen $bw $delta
        $bw.Write([byte[]]$evt.bytes)
        $lastTick = $evt.tick
    }

    # End of track
    $bw.Write([byte[]](0x00, 0xFF, 0x2F, 0x00))
    $bw.Flush()
    $trackData = $ms.ToArray()
    $ms.Dispose()

    # Write MTrk chunk to main stream
    $mainWriter.Write([byte[]](0x4D, 0x54, 0x72, 0x6B))
    $len = $trackData.Length
    $mainWriter.Write([byte](($len -shr 24) -band 0xFF))
    $mainWriter.Write([byte](($len -shr 16) -band 0xFF))
    $mainWriter.Write([byte](($len -shr 8) -band 0xFF))
    $mainWriter.Write([byte]($len -band 0xFF))
    $mainWriter.Write($trackData)
}

function Add-NoteEvents([System.Collections.Generic.List[hashtable]]$events, [int]$ch, [double]$t, [double]$freq, [double]$dur, [int]$vel) {
    $tick = SecsToTicks $t
    $note = FreqToMidi $freq
    $durTicks = SecsToTicks $dur
    if ($durTicks -lt 1) { $durTicks = 1 }
    $events.Add(@{tick=$tick; on=0; bytes=@([byte](0x90 -bor $ch), [byte]$note, [byte]$vel)})
    $events.Add(@{tick=($tick + $durTicks); on=1; bytes=@([byte](0x80 -bor $ch), [byte]$note, [byte]0)})
}

