# ══════════════════════════════════════════
# WRITE MIDI FILE
# ══════════════════════════════════════════
$fs = [System.IO.FileStream]::new($OutputFile, [System.IO.FileMode]::Create)
$mainBw = [System.IO.BinaryWriter]::new($fs)

# MThd header
$mainBw.Write([byte[]](0x4D, 0x54, 0x68, 0x64))  # "MThd"
$mainBw.Write([byte[]](0x00, 0x00, 0x00, 0x06))  # length=6
$mainBw.Write([byte[]](0x00, 0x01))               # format 1
$mainBw.Write([byte[]](0x00, 0x05))               # 5 tracks
$mainBw.Write([byte](($TPQ -shr 8) -band 0xFF))
$mainBw.Write([byte]($TPQ -band 0xFF))

# Write all tracks directly to main stream
Write-Track $mainBw "Jurassic (Sawtooth Bass)" 0 81 $jurEvents $true
Write-Track $mainBw "Medieval (Square Chords)" 1 80 $medEvents $false
Write-Track $mainBw "City (Triangle Pad)" 2 88 $cityEvents $false
Write-Track $mainBw "Space (Arpeggios)" 3 98 $spaceEvents $false
Write-Track $mainBw "Drums" 9 0 $drumEvents $false

$mainBw.Flush()
$mainBw.Close()
$fs.Close()

$size = (Get-Item $OutputFile).Length
Write-Host "MIDI file written to: $OutputFile"
Write-Host "Size: $size bytes"
Write-Host "Tracks: Jurassic (Ch0/GM82), Medieval (Ch1/GM81), City (Ch2/GM89), Space (Ch3/GM99), Drums (Ch10)"
Write-Host "BPM: $BPM | Loop: 13.7s | TPQ: $TPQ"
